import java.lang.reflect.Type;

public class GsonToJsonTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void testToJson_withNullObject_returnsJsonNull() {
    String json = gson.toJson(null, Object.class);
    assertEquals("null", json);
  }

  @Test
  public void testToJson_withStringObject_returnsJsonString() {
    String input = "testString";
    String json = gson.toJson(input, String.class);
    assertEquals("\"testString\"", json);
  }

  @Test
  public void testToJson_withIntegerObject_returnsJsonNumber() {
    Integer input = 123;
    String json = gson.toJson(input, Integer.class);
    assertEquals("123", json);
  }

  @Test
  public void testToJson_withComplexObject_returnsJsonRepresentation() {
    TestClass input = new TestClass();
    input.id = 1;
    input.name = "abc";
    String json = gson.toJson(input, TestClass.class);
    assertTrue(json.contains("\"id\":1"));
    assertTrue(json.contains("\"name\":\"abc\""));
  }

  @Test
  public void testToJson_invokesPrivateToJsonWithWriter() throws Exception {
    // Using reflection to invoke private method toJson(Object, Type, Appendable)
    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", Object.class, Type.class, Appendable.class);
    toJsonMethod.setAccessible(true);

    StringWriter writer = new StringWriter();
    toJsonMethod.invoke(gson, "reflectionTest", String.class, writer);

    String result = writer.toString();
    assertEquals("\"reflectionTest\"", result);
  }

  static class TestClass {
    int id;
    String name;
  }
}
